import{_ as i,o as l,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3135_凌航/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"審計報告庫/財務審計/3135_凌航/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),e={name:"審計報告庫/財務審計/3135_凌航/20260430/F16_大股東成本與籌碼結構審計_投資研究員.md"};function o(n,a,s,h,_,d){return l(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="f16-大股東成本與籌碼結構審計-投資研究員審計報告" tabindex="-1">F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計-投資研究員審計報告" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計 - 投資研究員審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：凌航家族控股37.14%，質押歸零，千張大戶從67%降至47%，籌碼分散化。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：2026/4/29</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>董監事合計持股：約49.64%</li><li>千張大戶佔比：67.65%（2023/5）→ 47.77%（2026/4/24），蒸發20個百分點</li><li>散戶人數：1,306人→11,588人，暴增787%</li></ul></li><li><strong>診斷見解</strong>：家族控股穩固，但上市後籌碼快速分散，大戶派發、散戶承接。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-董監事持股與增減趨勢" tabindex="-1">1. 董監事持股與增減趨勢 <a class="header-anchor" href="#_1-董監事持股與增減趨勢" aria-label="Permalink to &quot;1. 董監事持股與增減趨勢&quot;">​</a></h3><ul><li>前三大股東（盛耘22.42%、瑞瑞14.72%、泰特6.78%）合計43.92%，均為法人持股。泰特從4,117,081股增至5,250,291股（+27.5%），家族核心成員未減持。</li></ul><h3 id="_2-董監持股質押安全性壓力測試" tabindex="-1">2. 董監持股質押安全性壓力測試 <a class="header-anchor" href="#_2-董監持股質押安全性壓力測試" aria-label="Permalink to &quot;2. 董監持股質押安全性壓力測試&quot;">​</a></h3><ul><li>整體董監質押比例0.00%。泰特科技曾質押72.87%已完全解除，吳惠玲1.3%、曾萬全2.1%均屬極低水準。假設股價回檔50%，零質押狀態下無平倉風險。</li></ul><h3 id="_3-大戶持股成本估算" tabindex="-1">3. 大戶持股成本估算 <a class="header-anchor" href="#_3-大戶持股成本估算" aria-label="Permalink to &quot;3. 大戶持股成本估算&quot;">​</a></h3><ul><li>原始大戶成本推估NT$15-25，以目前NT$140計浮盈460%-833%。外資上市後平均成本推估約NT$60-90。</li></ul><h3 id="_4-籌碼集中度演變" tabindex="-1">4. 籌碼集中度演變 <a class="header-anchor" href="#_4-籌碼集中度演變" aria-label="Permalink to &quot;4. 籌碼集中度演變&quot;">​</a></h3><ul><li>千張大戶從67.65%降至47.77%（-1,988 bps），散戶從1,306人暴增至11,588人（+787%），400張以上大戶從82.32%降至62.47%。典型IPO後籌碼擴散模式，原始大戶解禁後系統性派發籌碼給散戶。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：<strong>籌碼結構惡化速度過快</strong>。千張大戶持股佔比從上市前的67.65%在9個月內驟降至47.77%，降幅達20個百分點。以歷史經驗，當千張大戶佔比跌破50%且持續下降時，股價上檔壓力將顯著增加。若此趨勢延續至2026年下半年，股價可能面臨30-40%的回調壓力。原始大戶浮盈400-800%，具備充足動機持續減持，且公司缺乏法人機構護盤（外資僅3.43%）。</li><li><strong>空頭風險二</strong>：<strong>PBR 5.09倍為記憶體模組股歷史高位</strong>。凌航從承銷價NT$28大漲至NT$140（+400%），PBR從1.6倍飆升至5.09倍。同業如群聯（8299）PBR約3-4倍、創見（2451）約2-3倍，凌航估值溢價明顯。若DRAM/NAND報價進入下行週期，高估值疊加籌碼分散將形成「雙殺」格局。</li><li><strong>對策建議</strong>：（1）密切追蹤千張大戶佔比月度變化，若跌破45%需啟動風控；（2）關注2026年6月股東會前後的內部人異動公告；（3）設定PBR回落至3.5倍以下為安全邊際區間。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (backer_holding)</strong>：OK。2023/5至2026/4/24全序列數據完整，股權分散表每週更新。</li><li><strong>FinMind (holding)</strong>：OK。外資持股從2025/8/6上市日0%至2026/4/29的3.43%完整記錄。</li><li><strong>FinMind (institutional)</strong>：OK。三大法人買賣超日資料完整。</li><li><strong>FinMind (per)</strong>：OK。PBR從上市首日1.6至2026/4/29的5.09完整記錄。</li><li><strong>年報 (2023_Q4_3135_合併.pdf)</strong>：OK。十大股東名單（第48頁）、董監持股與質押（第8-9、43頁）、股權分散表（第48頁）、關係人（第45頁）均已提取。</li><li><strong>Web Search (質押比例)</strong>：OK。Goodinfo/MOPS/Fubon資料交叉驗證，泰特科技72.87%→0%解除質押確認。</li><li><strong>Web Search (承銷價)</strong>：OK。多來源確認承銷價NT$28、競價拍賣均價NT$30.9。</li><li><strong>關鍵核對碼</strong>： <ul><li>十大股東合計：42,354,562股 / 60,373,405股 = 70.16%（2023年報）</li><li>盛耘+瑞瑞 = 27,793,196股 / 60,373,405股 = 46.03%（2023年報）</li><li>2026/4/24千張大戶：44,812,811股 / 93,802,057股 = 47.77%</li><li>外資持股：2,659,997股 / 77,493,405股 = 3.43%（2026/4/29）</li></ul></li></ul>',21)])])}const g=i(e,[["render",o]]);export{u as __pageData,g as default};
